import csv
import io

OPT_IN_IDS  = {"E010", "E012"}
OPT_OUT_IDS = {"E011", "E013"}

def test_opt_out_combinations_decision_table(
    hr_admin_token,       # <fixture>
    seed_dt_employees,    # <fixture> seeds E010-E013
    api_client,           # <fixture>
):
    resp = api_client.get(
        "/api/employees/export.csv",
        headers={"Authorization": f"Bearer {hr_admin_token}"},
    )
    assert resp.status_code == 200

    rows = {r["id"]: r for r in csv.DictReader(io.StringIO(resp.text))}

    for eid in OPT_IN_IDS:
        assert rows[eid]["email"] != "REDACTED", f"{eid} opted-in: email must be visible"
        assert rows[eid]["name"]  != "REDACTED", f"{eid} opted-in: name must be visible"

    for eid in OPT_OUT_IDS:
        assert rows[eid]["email"] == "REDACTED", f"{eid} opted-out: email must be redacted"
        assert rows[eid]["name"]  == "REDACTED", f"{eid} opted-out: name must be redacted"

def test_unauthenticated_export_returns_403(
    api_client,   # <fixture>
):
    resp = api_client.get("/api/employees/export.csv")
    assert resp.status_code in (401, 403), (
        f"expected 401 or 403 for unauthenticated request, got {resp.status_code}"
    )
    assert "text/csv" not in resp.headers.get("Content-Type", ""), (
        "no CSV payload must be returned for unauthenticated callers"
    )
